示例（保持语义）：

for (r=0;r<NR;r++)
  for (q=0;q<NQ;q++) {
    // sum 清零
    for (p=0;p<NP;p++) sum[p]=0;

    const DATA_TYPE * __restrict arow = &A[r][q][0];
    for (int ss=0; ss<NP; ss++) {
      DATA_TYPE a = arow[ss];
      const DATA_TYPE * __restrict c4row = &C4[ss][0];
      // p 分块，利于向量化与缓存
      for (int pp=0; pp<NP; pp+=TP) {
        #pragma omp simd
        for (int p=pp; p<pp+TP && p<NP; p++)
          sum[p] += a * c4row[p];
      }
    }
    // 写回
    for (p=0;p<NP;p++) A[r][q][p]=sum[p];
  }

其中 TP 可取 32/64/128（按 SIMD 宽度与 L1 容量调参）。

并行化外层：
#pragma omp parallel
{
  // 每线程私有 sum，避免共享写
  DATA_TYPE *sum_priv = (DATA_TYPE*) aligned_alloc(64, NP*sizeof(DATA_TYPE));

  #pragma omp for collapse(2) schedule(static)
  for (int r=0;r<NR;r++)
    for (int q=0;q<NQ;q++) {
      for (int p=0;p<NP;p++) sum_priv[p]=0;
      for (int s=0;s<NP;s++) {
        DATA_TYPE a = A[r][q][s];
        #pragma omp simd
        for (int p=0;p<NP;p++) sum_priv[p] += a * C4[s][p];
      }
      for (int p=0;p<NP;p++) A[r][q][p]=sum_priv[p];
    }

  free(sum_priv);
}

注意：不要复用原全局 sum（否则线程间冲突）。

示例（寄存器 tile，适合 NP 大且 SIMD 友好）：
for (int pp=0; pp<NP; pp+=TP) {
  DATA_TYPE acc[TP];
  for (int i=0;i<TP;i++) acc[i]=0;
  for (int s=0;s<NP;s++) {
    DATA_TYPE a=A[r][q][s];
    #pragma omp simd
    for (int i=0;i<TP && pp+i<NP;i++) acc[i]+=a*C4[s][pp+i];
  }
  for (int i=0;i<TP && pp+i<NP;i++) A[r][q][pp+i]=acc[i];
}

这样可去掉对 sum[] 的反复读写（只在寄存器中累加）。
